                }
                isPrime[jInt] = false
                j += i
            }
        }
    }

    val primeToIndices = mutableMapOf<Int, MutableList<Int>>()
    for (i in nums.indices) {
        val num = nums[i].toInt()
        if (num < 2) continue
        var temp = num
        val set = mutableSetOf<Int>()
        while (temp > 1) {
            val p = spf[temp]
            set.add(p)
            while (temp % p == 0) {
                temp /= p
            }
        }
        for (p in set) {
            primeToIndices.getOrPut(p) { mutableListOf() }.add(i)
        }
    }

    val dist = IntArray(n) { -1 }
    val usedPrimes = BooleanArray(MAX_VAL + 1) { false }
