        val i = queue.poll()
        if (i == n - 1) {
            return dist[i].toLong()
        }
        if (i - 1 >= 0 && dist[i - 1] == -1) {
            dist[i - 1] = dist[i] + 1
            queue.add(i - 1)
        }
        if (i + 1 < n && dist[i + 1] == -1) {
            dist[i + 1] = dist[i] + 1
            queue.add(i + 1)
        }
        val num = nums[i].toInt()
        if (num >= 2 && isPrime[num]) {
            val p = num
            if (!usedPrimes[p]) {
